public static UBSAutomaticReceptionBatchController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    UBSAutomaticReceptionBatchController controller = new UBSAutomaticReceptionBatchController();
    controller.parmExecutionMode(_executionMode);
    return controller;
}

public static void main(Args _args)
{
    UBSAutomaticReceptionBatchController controller = UBSAutomaticReceptionBatchController::construct();
    controller.parmArgs(_args);
    controller.startOperation();
}
